import{_ as e,o as s,c as t,a2 as n}from"./chunks/framework.DeNJmwJc.js";const m=JSON.parse('{"title":"Chapter 37 ŌĆö Macros","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/37-macros.md","filePath":"chapters/37-macros.md"}'),i={name:"chapters/37-macros.md"};function o(p,a,r,c,l,d){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="chapter-37-ŌĆö-macros" tabindex="-1">Chapter 37 ŌĆö Macros <a class="header-anchor" href="#chapter-37-ŌĆö-macros" aria-label="Permalink to &quot;Chapter 37 ŌĆö Macros&quot;">ŌĆŗ</a></h1><blockquote><p><em>&quot;Record a sequence of commands once, replay it hundreds of times.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ŌŁÉŌŁÉŌŁÉŌŁÉ Advanced <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">ŌĆŗ</a></h1><p>Macros let you record a sequence of Vim commands and replay them.</p><p>They are stored in registers.</p><hr><h1 id="recording-a-macro" tabindex="-1">Recording a Macro <a class="header-anchor" href="#recording-a-macro" aria-label="Permalink to &quot;Recording a Macro&quot;">ŌĆŗ</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>qa</code></td><td>Start recording macro into register <code>a</code></td></tr><tr><td>(commands)</td><td>Your sequence of actions</td></tr><tr><td><code>q</code></td><td>Stop recording</td></tr></tbody></table><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">ŌĆŗ</a></h2><p>Record a macro that adds a semicolon to the end of a line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qa      ŌåÆ   Start recording into register a</span></span>
<span class="line"><span>A;      ŌåÆ   Append semicolon</span></span>
<span class="line"><span>Esc     ŌåÆ   Return to normal mode</span></span>
<span class="line"><span>j       ŌåÆ   Move down</span></span>
<span class="line"><span>q       ŌåÆ   Stop recording</span></span></code></pre></div><hr><h1 id="playing-a-macro" tabindex="-1">Playing a Macro <a class="header-anchor" href="#playing-a-macro" aria-label="Permalink to &quot;Playing a Macro&quot;">ŌĆŗ</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>@a</code></td><td>Execute macro from register <code>a</code></td></tr><tr><td><code>@@</code></td><td>Repeat last macro</td></tr><tr><td><code>10@a</code></td><td>Execute macro <code>a</code> 10 times</td></tr></tbody></table><hr><h1 id="practical-example" tabindex="-1">Practical Example <a class="header-anchor" href="#practical-example" aria-label="Permalink to &quot;Practical Example&quot;">ŌĆŗ</a></h1><p>Suppose you have:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Line 1</span></span>
<span class="line"><span>Line 2</span></span>
<span class="line"><span>Line 3</span></span>
<span class="line"><span>Line 4</span></span>
<span class="line"><span>Line 5</span></span></code></pre></div><p>Record:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qa      ŌåÆ   Start recording</span></span>
<span class="line"><span>0       ŌåÆ   Go to start of line</span></span>
<span class="line"><span>i*      ŌåÆ   Insert * at beginning</span></span>
<span class="line"><span>Esc     ŌåÆ   Normal mode</span></span>
<span class="line"><span>j       ŌåÆ   Next line</span></span>
<span class="line"><span>q       ŌåÆ   Stop recording</span></span></code></pre></div><p>Then:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3@a     ŌåÆ   Apply to next 3 lines</span></span></code></pre></div><p>Result:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*Line 1</span></span>
<span class="line"><span>*Line 2</span></span>
<span class="line"><span>*Line 3</span></span>
<span class="line"><span>*Line 4</span></span>
<span class="line"><span>*Line 5</span></span></code></pre></div><hr><h1 id="editing-a-macro" tabindex="-1">Editing a Macro <a class="header-anchor" href="#editing-a-macro" aria-label="Permalink to &quot;Editing a Macro&quot;">ŌĆŗ</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:let @a = &#39;commands&#39;</span></span></code></pre></div><p>Manually set a macro.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:let @a = &#39;0i*&#39; . &quot;\\&lt;Esc&gt;&quot; . &#39;j&#39;</span></span></code></pre></div><p>Set macro with special keys.</p><hr><h1 id="appending-to-a-macro" tabindex="-1">Appending to a Macro <a class="header-anchor" href="#appending-to-a-macro" aria-label="Permalink to &quot;Appending to a Macro&quot;">ŌĆŗ</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qA      ŌåÆ   Append to existing macro in register a</span></span></code></pre></div><p>Capital letter = append.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">ŌĆŗ</a></h1><ul><li><code>qa</code> records, <code>q</code> stops.</li><li><code>@a</code> plays, <code>@@</code> repeats.</li><li>Macros can combine any Vim commands.</li><li>Use macros for repetitive edits.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">ŌĆŗ</a></h2><ol><li>Record a macro that adds <code># </code> to the start of a line.</li><li>Record a macro that wraps text in quotes.</li><li>Execute the macro 5 times.</li><li>Use <code>@@</code> to repeat.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">ŌĆŗ</a></h2><p><a href="./38-buffers.html"><strong>Chapter 38 ŌĆö Buffers</strong></a></p><p>Work with multiple files using Vim&#39;s buffer system.</p>`,47)])])}const u=e(i,[["render",o]]);export{m as __pageData,u as default};
